import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { ApiService } from './api.service';
import { CourseGradebookDto, LearnerGradesDto, OrgGradebookDto } from '../models/gradebook.models';

@Injectable({ providedIn: 'root' })
export class GradebookService {
  constructor(private api: ApiService) {}

  getCourseGradebook(courseId: number): Observable<CourseGradebookDto> {
    return this.api.get<CourseGradebookDto>(`gradebook/course/${courseId}`);
  }

  getLearnerGrades(courseId: number, userId: number): Observable<LearnerGradesDto> {
    return this.api.get<LearnerGradesDto>(`gradebook/course/${courseId}/learner/${userId}`);
  }

  getOrgGradebook(courseId: number, orgId: number): Observable<OrgGradebookDto> {
    return this.api.get<OrgGradebookDto>(`gradebook/course/${courseId}/org/${orgId}`);
  }
}
